mapper.select:
SELECT b.booking_id, b.booking_number, b.user_id, u.login_id AS user_login_id, b.product_id, p.product_name, b.name, b.phone, b.email, b.adult_count, b.child_count, b.infant_count, b.desired_departure_at, b.total_price, b.request_memo, b.status, b.admin_memo, b.admin_checked, b.payment_status, b.payment_method, b.paid_amount, b.paid_at, b.pg_transaction_id, b.created_at, b.updated_at FROM bookings b LEFT JOIN users u ON b.user_id = u.user_id LEFT JOIN products p ON b.product_id = p.product_id
AND (b.name ILIKE '%' || #{keyword} || '%' OR b.phone ILIKE '%' || #{keyword} || '%' OR b.email ILIKE '%' || #{keyword} || '%' OR p.product_name ILIKE '%' || #{keyword} || '%' OR b.booking_number ILIKE '%' || #{keyword} || '%')
AND b.status = #{status}
AND b.payment_status = #{paymentStatus}
AND b.product_id = #{productId}
ORDER BY b.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT b.booking_id, b.booking_number, b.user_id, u.login_id AS user_login_id, b.product_id, p.product_name, COALESCE(c1.category_name, c2.category_name) AS root_category_name, b.name, b.phone, b.email, b.adult_count, b.child_count, b.infant_count, b.desired_departure_at, b.total_price, b.request_memo, b.status, b.admin_memo, b.admin_checked, b.payment_status, b.payment_method, b.paid_amount, b.paid_at, b.pg_transaction_id, b.created_at, b.updated_at FROM bookings b LEFT JOIN users u ON b.user_id = u.user_id LEFT JOIN products p ON b.product_id = p.product_id LEFT JOIN categories c2 ON p.category_id = c2.category_id LEFT JOIN categories c1 ON c2.parent_id = c1.category_id
AND (b.name ILIKE '%' || #{keyword} || '%' OR b.phone ILIKE '%' || #{keyword} || '%' OR b.email ILIKE '%' || #{keyword} || '%' OR p.product_name ILIKE '%' || #{keyword} || '%' OR b.booking_number ILIKE '%' || #{keyword} || '%')
AND b.status = #{status}
AND b.payment_status = #{paymentStatus}
AND b.product_id = #{productId}
ORDER BY b.created_at DESC

SELECT COUNT(*) FROM bookings b LEFT JOIN products p ON b.product_id = p.product_id
AND (b.name ILIKE '%' || #{keyword} || '%' OR b.phone ILIKE '%' || #{keyword} || '%' OR b.email ILIKE '%' || #{keyword} || '%' OR p.product_name ILIKE '%' || #{keyword} || '%' OR b.booking_number ILIKE '%' || #{keyword} || '%')
AND b.status = #{status}
AND b.payment_status = #{paymentStatus}
AND b.product_id = #{productId}

mapper.update:
UPDATE bookings
SET status = #{status}, updated_at = NOW()
WHERE booking_id = #{bookingId}

UPDATE bookings
SET admin_memo = #{adminMemo}, updated_at = NOW()
WHERE booking_id = #{bookingId}

UPDATE bookings
SET admin_checked = true, updated_at = NOW()
WHERE booking_id = #{bookingId}

mapper.delete:
DELETE FROM bookings
WHERE booking_id = #{bookingId}
  AND user_id    = #{userId}
  AND status     = 'PENDING'
